// ── Validate & Normalize Input ──────────────────────────────
const body = $input.first().json.body || $input.first().json;

// Required fields
const required = [
  'revolving_util', 'age', 'late_30_59', 'debt_ratio',
  'monthly_income', 'open_credit_lines', 'late_90',
  'real_estate_loans', 'late_60_89', 'dependents'
];

const missing = required.filter(f => body[f] === undefined || body[f] === null || body[f] === '');
if (missing.length > 0) {
  throw new Error(`Missing required fields: ${missing.join(', ')}`);
}

// Range validation
const errors = [];
const age            = parseInt(body.age);
const revolving_util = parseFloat(body.revolving_util);
const monthly_income = parseFloat(body.monthly_income);
const debt_ratio     = parseFloat(body.debt_ratio);
const late_30_59     = parseInt(body.late_30_59);
const late_60_89     = parseInt(body.late_60_89);
const late_90        = parseInt(body.late_90);

if (isNaN(age) || age < 18 || age > 120)               errors.push('age must be 18-120');
if (isNaN(revolving_util) || revolving_util < 0 || revolving_util > 1) errors.push('revolving_util must be 0.0-1.0');
if (isNaN(monthly_income) || monthly_income <= 0)       errors.push('monthly_income must be > 0');
if (isNaN(debt_ratio) || debt_ratio < 0)               errors.push('debt_ratio cannot be negative');
if (isNaN(late_30_59) || late_30_59 < 0)               errors.push('late_30_59 cannot be negative');
if (isNaN(late_60_89) || late_60_89 < 0)               errors.push('late_60_89 cannot be negative');
if (isNaN(late_90)    || late_90 < 0)                  errors.push('late_90 cannot be negative');

if (errors.length > 0) {
  throw new Error(`Validation failed: ${errors.join(' | ')}`);
}

// Generate applicant ID if not provided
const applicant_id = body.applicant_id || `APP-${Date.now()}`;

return [{
  json: {
    applicant_id,
    source:            'API Webhook',
    received_at:       new Date().toISOString(),
    revolving_util,
    age,
    late_30_59,
    debt_ratio,
    monthly_income,
    open_credit_lines: parseInt(body.open_credit_lines),
    late_90,
    real_estate_loans: parseInt(body.real_estate_loans),
    late_60_89,
    dependents:        parseInt(body.dependents)
  }
}];

// ── Merge ML result with original input ─────────────────────
const ml    = $input.first().json;
const input = $('Validate & Normalize').first().json;

const factors = ml.top_risk_factors || [];

const riskEmoji = { HIGH: '🔴', MEDIUM: '🟡', LOW: '🟢' }[ml.risk_level] || '⚪';

const report = {
  // ── Identity ──
  applicant_id:           input.applicant_id,
  source:                 input.source,
  timestamp:              new Date().toISOString(),
  received_at:            input.received_at,

  // ── Input Features ──
  age:                    input.age,
  monthly_income:         input.monthly_income,
  debt_ratio:             input.debt_ratio,
  revolving_util:         input.revolving_util,
  late_30_59:             input.late_30_59,
  late_60_89:             input.late_60_89,
  late_90:                input.late_90,
  open_credit_lines:      input.open_credit_lines,
  real_estate_loans:      input.real_estate_loans,
  dependents:             input.dependents,

  // ── ML Output ──
  default_probability:    ml.default_probability,
  default_probability_pct:`${(ml.default_probability * 100).toFixed(1)}%`,
  risk_level:             ml.risk_level,
  risk_emoji:             riskEmoji,
  prediction:             ml.prediction === 1 ? 'WILL DEFAULT' : 'WILL NOT DEFAULT',
  recommendation:         ml.recommendation,
  risk_factor_1:          factors[0] || 'N/A',
  risk_factor_2:          factors[1] || 'N/A',
  risk_factor_3:          factors[2] || 'N/A',
  model:                  ml.model,
  threshold_used:         ml.threshold_used,

  // ── Flags ──
  is_high_risk:           ml.risk_level === 'HIGH',
  filename:               `LoanSense_${input.applicant_id}_${Date.now()}.html`
};

return [{ json: report }];

// ── Generate styled HTML report ─────────────────────────────
const r = $input.first().json;

const colors = { HIGH: '#e74c3c', MEDIUM: '#f39c12', LOW: '#2ecc71' };
const color  = colors[r.risk_level] || '#95a5a6';

const html = `<!DOCTYPE html>
<html lang="en">
<head>
  <meta charset="UTF-8">
  <meta name="viewport" content="width=device-width, initial-scale=1.0">
  <title>LoanSense Report — ${r.applicant_id}</title>
  <style>
    * { box-sizing: border-box; margin: 0; padding: 0; }
    body { font-family: 'Segoe UI', Arial, sans-serif; background: #f0f2f5; padding: 30px; color: #2c3e50; }
    .card { background: white; border-radius: 12px; padding: 30px; margin-bottom: 20px; box-shadow: 0 2px 8px rgba(0,0,0,0.08); }
    .header { background: linear-gradient(135deg, #2c3e50, #34495e); color: white; border-radius: 12px; padding: 30px; margin-bottom: 20px; }
    .header h1 { font-size: 26px; margin-bottom: 6px; }
    .header p  { opacity: 0.75; font-size: 13px; }
    .badge { display: inline-block; background: ${color}; color: white; padding: 8px 22px; border-radius: 20px; font-size: 20px; font-weight: 700; margin: 12px 0; }
    .prob { font-size: 42px; font-weight: 800; color: ${color}; }
    .prob-label { font-size: 12px; color: #7f8c8d; text-transform: uppercase; letter-spacing: 1px; margin-bottom: 4px; }
    .section-title { font-size: 13px; font-weight: 700; text-transform: uppercase; letter-spacing: 1px; color: #7f8c8d; margin-bottom: 16px; border-bottom: 2px solid #f0f2f5; padding-bottom: 8px; }
    .grid { display: grid; grid-template-columns: 1fr 1fr; gap: 12px; }
    .grid-3 { display: grid; grid-template-columns: 1fr 1fr 1fr; gap: 12px; }
    .stat { background: #f8f9fa; border-radius: 8px; padding: 14px; }
    .stat-label { font-size: 11px; color: #95a5a6; text-transform: uppercase; margin-bottom: 4px; }
    .stat-value { font-size: 20px; font-weight: 700; color: #2c3e50; }
    .factor { background: #fff5f5; border-left: 4px solid ${color}; border-radius: 0 8px 8px 0; padding: 12px 16px; margin-bottom: 10px; font-size: 14px; }
    .recommendation { background: ${color}; color: white; border-radius: 10px; padding: 18px 24px; font-size: 17px; font-weight: 700; text-align: center; margin-bottom: 20px; }
    .footer { text-align: center; color: #bdc3c7; font-size: 12px; padding-top: 10px; }
    .divider { height: 1px; background: #f0f2f5; margin: 16px 0; }
  </style>
</head>
<body>

  <div class="header">
    <h1>🏦 LoanSense Risk Report</h1>
    <p>Applicant: <strong>${r.applicant_id}</strong> &nbsp;·&nbsp; ${new Date(r.timestamp).toLocaleString()} &nbsp;·&nbsp; Source: ${r.source}</p>
  </div>

  <div class="card">
    <div class="section-title">Risk Assessment</div>
    <div class="prob-label">Default Probability</div>
    <div class="prob">${r.default_probability_pct}</div>
    <div class="badge">${r.risk_emoji} ${r.risk_level} RISK</div>
    <div class="divider"></div>
    <div class="grid">
      <div class="stat">
        <div class="stat-label">Prediction</div>
        <div class="stat-value" style="font-size:15px">${r.prediction}</div>
      </div>
      <div class="stat">
        <div class="stat-label">Model</div>
        <div class="stat-value" style="font-size:15px">${r.model}</div>
      </div>
    </div>
  </div>

  <div class="recommendation">${r.recommendation}</div>

  <div class="card">
    <div class="section-title">Top Risk Factors</div>
    <div class="factor">⚠️ &nbsp;${r.risk_factor_1}</div>
    <div class="factor">⚠️ &nbsp;${r.risk_factor_2}</div>
    <div class="factor">⚠️ &nbsp;${r.risk_factor_3}</div>
  </div>

  <div class="card">
    <div class="section-title">Applicant Details</div>
    <div class="grid-3">
      <div class="stat"><div class="stat-label">Age</div><div class="stat-value">${r.age}</div></div>
      <div class="stat"><div class="stat-label">Monthly Income</div><div class="stat-value">$${r.monthly_income.toLocaleString()}</div></div>
      <div class="stat"><div class="stat-label">Debt Ratio</div><div class="stat-value">${r.debt_ratio}</div></div>
      <div class="stat"><div class="stat-label">Credit Utilization</div><div class="stat-value">${(r.revolving_util*100).toFixed(0)}%</div></div>
      <div class="stat"><div class="stat-label">Late 30-59 Days</div><div class="stat-value">${r.late_30_59}</div></div>
      <div class="stat"><div class="stat-label">Late 60-89 Days</div><div class="stat-value">${r.late_60_89}</div></div>
      <div class="stat"><div class="stat-label">Late 90+ Days</div><div class="stat-value">${r.late_90}</div></div>
      <div class="stat"><div class="stat-label">Open Credit Lines</div><div class="stat-value">${r.open_credit_lines}</div></div>
      <div class="stat"><div class="stat-label">Real Estate Loans</div><div class="stat-value">${r.real_estate_loans}</div></div>
      <div class="stat"><div class="stat-label">Dependents</div><div class="stat-value">${r.dependents}</div></div>
    </div>
  </div>

  <div class="footer">
    <p>LoanSense v1.0 &nbsp;·&nbsp; Model: ${r.model} &nbsp;·&nbsp; Threshold: ${r.threshold_used} &nbsp;·&nbsp; Generated: ${new Date(r.timestamp).toLocaleString()}</p>
  </div>

</body>
</html>`;

return [{ json: { ...r, html_report: html } }];
